var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>3년전, 북방합의체의 어느 연구소</color>","JPN":"<color=#ffd34c>3年前、北方合意体のとある研究所</color>","ENG":"<color=#ffd34c>3 years ago, One research lab in the Northern Union</color>","TWN":"<color=#ffd34c>3年前， 北方和議會某研究所</color>","SCN":"<color=#ffd34c>3年前， 北方联盟某研究所</color>","DEU":"<color=#ffd34c>3 years ago, One research lab in the Northern Union</color>","FRA":"<color=#ffd34c>3 years ago, One research lab in the Northern Union</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"사샤의 상태는?","JPN":"サシャの状態は？","ENG":"How's Sasha doing?","TWN":"莎夏的情況如何？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"카운터 능력이 발현되었지만, 거의 사용하려 하지 않네요.","JPN":"カウンター能力が発現しましたが、まったく使おうとしません。","ENG":"Her Counter ability has been activated, but she hardly uses it.","TWN":"雖然制裁者能力已經顯現，但幾乎不怎麼使用。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"발현하다 만 케이스도 많으니까, 좀 더 지켜봐야겠지.","JPN":"発現の途中で中断されるケースも多いから、もう少し見守るべきだろう。","ENG":"There are many cases where Counter abilities don't fully manifest, so we'll have to wait and see.","TWN":"有很多個顯現部分能力的案例，還需要再觀察。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"그림자로 변이되면 어떻게 다룰 수 있을지도 생각해 봐야겠습니다.","JPN":"シャドウに変異したら、どう対処するかも考えておかないとですね。","ENG":"For now, we should think about how to handle her if she turns into a Shadow.","TWN":"如果變成暗影，還得考慮怎麼處理。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"마음 아프게 됐군.","JPN":"心が痛むな。","ENG":"That's heartbreaking.","TWN":"那真是令人心痛。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"그런 말도 할 줄 아시네요 박사님.","JPN":"博士はそんな言葉も知っているんですね。","ENG":"So you do know how to say things like that, Doctor.","TWN":"博士也會說這種話嗎？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"……특이증상에 대해서 다시 말해주게.","JPN":"……特異症状についてもう一度聞かせてくれ。","ENG":"...Tell me again about her specific symptoms.","TWN":"……再說一遍關於特殊症狀的事。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"현재까지 발견된 증상으로는 총 2가지입니다.","JPN":"今まで発見された症状としては、2つあります。","ENG":"Currently, there are two symptoms discovered.","TWN":"目前發現的症狀總共有兩種。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>불규칙적으로 일어나는 고열.</color>","JPN":"<color=#ffd34c>不規則に発生する高熱。</color>","ENG":"The <color=#ffd34c>irregular occurrence of fever breaks,</color>","TWN":"<color=#ffd34c>不規律的高燒</color>。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"그리고 <color=#ffd34c>기면증</color> 정도가 있습니다.","JPN":"そして<color=#ffd34c>嗜眠</color>です。","ENG":"and the other is <color=#ffd34c>narcolepsy</color>.","TWN":"還有<color=#ffd34c>嗜睡症</color>。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"잠이란 건 죽음에 대비해 미리 연습하는 거라는 말이 있었잖아요?","JPN":"眠りとは、死に備えての予行練習だというじゃないですか。","ENG":"You know how people say that sleeping is just preparing for death?","TWN":"不是有句話說，睡眠是為了預先練習死亡嗎？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"그렇게 생각하니 조금 마음이 묘해지네요.","JPN":"そう思うと、少し妙な気持ちになりますね。","ENG":"Thinking about it like that makes me feel a little strange.","TWN":"這麼一想，心情有點複雜呢。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"죽음이라….","JPN":"死か……","ENG":"Death...","TWN":"死亡啊……"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"비상입니다! 사샤가 도주한 것 같습니다!","JPN":"非常事態です！　サシャが逃走したようです！","ENG":"Critical alert! Sasha has run away!","TWN":"緊急情況！莎夏好像逃跑了！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"어떻게…?! 지금 카메라에도 얌전히 앉아 있는거로 보이는데요?","JPN":"どうやって……！？　今、カメラには大人しく座ってるように見えますけど？","ENG":"How...?! The camera shows her sitting quietly!","TWN":"怎麼可能……？！現在鏡頭裡還看到她乖乖坐著呢？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"능력으로 조작한 것 같습니다! 카메라에 비친 건 가짜라고요!","JPN":"能力で捏造したみたいです！　カメラに映っているのは偽物ですよ！","ENG":"I think she manipulated it with her ability! What's shown on camera is a fake!","TWN":"好像是用能力操控的！鏡頭裡的是假的！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"박사님, 병사들을 전부 풀어 수색해야 합니다!","JPN":"博士、全兵士を動員して捜索すべきです！","ENG":"Doctor, we must send all our soldiers to search for her!","TWN":"博士，要派出所有士兵進行搜查嗎！"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"잠깐, 그냥 내버려두게.","JPN":"待て、放っておけ。","ENG":"Wait, just leave her be.","TWN":"等一下，先放著不管吧。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SIDEKICK_DOLL_NPC_NULL","text":{"KOREA":"뭐, 뭐라구요?","JPN":"な、なんて言いました？","ENG":"W-what?","TWN":"什，什麼？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"실험실에만 가둬놔도 유의미한 결과가 나올 거란 보장은 없지.","JPN":"実験室に閉じ込めておいても有意義な結果が出るという保証はない。","ENG":"There is no guarantee that we will get meaningful results locking her up in a lab.","TWN":"就算只關在實驗室裡，也不能保證會出現有意義的結果。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"어차피 그림자로 변이되는 것은 기정사실일세.","JPN":"どうせシャドウに変異することは既定事実だ。","ENG":"It's given that she'll turn into a Shadow.","TWN":"反正變成暗影是既定事實。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"우리의 연구가 어떤 결과를 맞이할지 직접 확인해 보지.","JPN":"我々の研究がどんな結果を向かえるのか、直接確認してみよう。","ENG":"Let's see for ourselves what outcomes our research will bring.","TWN":"就這麼看看我們的研究會變成什麼樣吧。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIDEKICK_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"하아… 하아…!","JPN":"はあ……はあ……！","ENG":"*Huff* *Huff*","TWN":"哈啊…哈啊…！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마을이구나… 성공이야…!","JPN":"村だ……成功だね……！","ENG":"It's a village...! I made it...!","TWN":"是村子……成功了……！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};